import{_ as a,o,c as e,a3 as d}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"目录清洁工具","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/directory-janitor.md","filePath":"user-guide/tools/directory-janitor.md","lastUpdated":1784173150000}'),r={name:"user-guide/tools/directory-janitor.md"};function s(n,t,l,i,c,h){return o(),e("div",null,[...t[0]||(t[0]=[d(`<h1 id="目录清洁工具" tabindex="-1">目录清洁工具 <a class="header-anchor" href="#目录清洁工具" aria-label="Permalink to &quot;目录清洁工具&quot;">​</a></h1><blockquote><p>智能清理过时的缓存、存档和临时文件，让磁盘空间&quot;呼吸&quot;起来。</p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>目录清洁工具帮你<strong>精准、安全</strong>地清理磁盘空间，核心能力包括：</p><ul><li><strong>🕵️ 按规则扫描</strong> — 支持按文件名模式（glob）、文件年龄（天）、文件大小（MB）组合过滤，精准定位目标</li><li><strong>♻️ 安全清理到回收站</strong> — 所有被清理的文件移至系统回收站，误删可恢复，无需担心</li><li><strong>⚡ Rust 后端驱动</strong> — 扫描清理由原生 Rust 后端执行，处理大量文件时依然丝滑流畅</li><li><strong>📊 实时进度反馈</strong> — 扫描和清理过程实时显示进度，支持随时取消</li><li><strong>📋 内置预设场景</strong> — 一键应用针对 VS Code 检查点、<code>node_modules</code>、编译产物等常见场景的预设配置</li><li><strong>🔍 结果二次筛选</strong> — 扫描结果出来后，还可以在结果面板中按名称、年龄、大小进一步过滤</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="_1-打开工具" tabindex="-1">1. 打开工具 <a class="header-anchor" href="#_1-打开工具" aria-label="Permalink to &quot;1. 打开工具&quot;">​</a></h3><p>在左侧工具栏中找到 <strong>目录清洁工具</strong>（图标为 🗑️），点击进入。</p><h3 id="_2-配置扫描参数" tabindex="-1">2. 配置扫描参数 <a class="header-anchor" href="#_2-配置扫描参数" aria-label="Permalink to &quot;2. 配置扫描参数&quot;">​</a></h3><p>在左侧<strong>配置面板</strong>中，依次设置：</p><table tabindex="0"><thead><tr><th>参数</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><strong>目标路径</strong></td><td>要扫描的目录，支持环境变量</td><td><code>C:/Projects</code>、<code>%UserProfile%/Downloads</code></td></tr><tr><td><strong>名称模式</strong></td><td>文件名匹配规则（glob 格式），空字符串匹配所有</td><td><code>node_modules</code>、<code>*.tmp</code>、<code>dist|build</code></td></tr><tr><td><strong>最小文件年龄</strong></td><td>文件多久没被修改才纳入清理</td><td><code>30</code> → 30 天以上未修改</td></tr><tr><td><strong>最小文件大小</strong></td><td>文件至少多大才纳入清理</td><td><code>100</code> → 100 MB 以上</td></tr><tr><td><strong>最大扫描深度</strong></td><td>递归扫描的最大子目录层级</td><td><code>3</code> → 最多往下翻 3 层</td></tr></tbody></table><blockquote><p><strong>💡 提示</strong>: 参数留空表示&quot;不限制&quot;。比如不填&quot;最小文件年龄&quot;和&quot;最小文件大小&quot;，只填名称模式 <code>*.log</code>，就会扫描出目标路径下<strong>所有</strong> <code>.log</code> 文件。</p></blockquote><h3 id="_3-开始扫描" tabindex="-1">3. 开始扫描 <a class="header-anchor" href="#_3-开始扫描" aria-label="Permalink to &quot;3. 开始扫描&quot;">​</a></h3><p>点击 <strong>&quot;开始扫描&quot;</strong> 按钮，工具会启动 Rust 后端遍历目录。右侧结果面板会实时显示扫描进度。</p><h3 id="_4-预览结果-勾选目标" tabindex="-1">4. 预览结果，勾选目标 <a class="header-anchor" href="#_4-预览结果-勾选目标" aria-label="Permalink to &quot;4. 预览结果，勾选目标&quot;">​</a></h3><p>扫描完成后，结果面板会列出匹配的文件和目录，包含名称、大小、修改时间等信息。</p><ul><li><strong>勾选</strong>需要清理的项目（全选 / 反选）</li><li>利用结果面板上方的<strong>二次筛选条件</strong>进一步缩小范围（如只看 100MB 以上的文件）</li><li>面板顶部会显示&quot;已选 N 项，共 X MB&quot;，帮你确认</li></ul><h3 id="_5-执行清理" tabindex="-1">5. 执行清理 <a class="header-anchor" href="#_5-执行清理" aria-label="Permalink to &quot;5. 执行清理&quot;">​</a></h3><p>点击 <strong>&quot;清理所选&quot;</strong>，系统会弹出确认对话框，显示要删除的数量和总大小。</p><p>确认后，文件将被移动到<strong>回收站</strong>。</p><blockquote><p><img src="" alt="TODO: 清理确认弹窗截图"></p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="预设配置" tabindex="-1">预设配置 <a class="header-anchor" href="#预设配置" aria-label="Permalink to &quot;预设配置&quot;">​</a></h3><p>内置的预设规则覆盖了常见清理场景，点击配置面板顶部的预设按钮即可一键填入参数：</p><table tabindex="0"><thead><tr><th>预设名称</th><th>针对场景</th><th>默认参数</th></tr></thead><tbody><tr><td><strong>Kilo Code 检查点</strong></td><td>Kilo Code 任务的 .git 检查点缓存</td><td>路径: AppData 下的 tasks，名称: <code>checkpoints</code>，7 天以上</td></tr><tr><td><strong>Roo Cline 检查点</strong></td><td>Roo Cline 任务的 .git 检查点缓存</td><td>同上</td></tr><tr><td><strong>VS Code 扩展缓存</strong></td><td>扩展产生的缓存文件</td><td>名称: <code>*.cache</code>，30 天以上，&gt;= 10MB</td></tr><tr><td><strong>Node.js 项目依赖</strong></td><td>长期不用的 node_modules</td><td>名称: <code>node_modules</code>，30 天以上，&gt;= 100MB</td></tr><tr><td><strong>编译产物</strong></td><td>dist / build / out / target 目录</td><td>名称: <code>dist|build|out|target</code>，14 天以上，&gt;= 10MB</td></tr><tr><td><strong>临时文件夹</strong></td><td>系统临时文件</td><td>全部文件，7 天以上，&gt;= 1MB</td></tr></tbody></table><blockquote><p><img src="" alt="TODO: 预设下拉菜单截图"></p></blockquote><h3 id="二次筛选" tabindex="-1">二次筛选 <a class="header-anchor" href="#二次筛选" aria-label="Permalink to &quot;二次筛选&quot;">​</a></h3><p>扫描结果出来之后，结果面板顶部提供<strong>独立的过滤条件</strong>（名称、最小年龄、最小大小）。与扫描参数不同，这些过滤条件<strong>只作用于已有结果</strong>，不需要重新扫描。</p><ul><li><strong>场景示例</strong>: 先扫描整个项目目录，然后在结果中只看 <code>node_modules</code> 文件夹、且大于 500MB 的项目</li><li>筛选条件激活时，面板顶部会显示&quot;已激活&quot;标识，方便取消</li></ul><h3 id="停止扫描-清理" tabindex="-1">停止扫描 / 清理 <a class="header-anchor" href="#停止扫描-清理" aria-label="Permalink to &quot;停止扫描 / 清理&quot;">​</a></h3><p>无论是扫描还是清理，都可以随时点击 <strong>&quot;停止&quot;</strong> 按钮终止操作。后端会响应取消指令并立即停止。</p><h3 id="环境变量支持" tabindex="-1">环境变量支持 <a class="header-anchor" href="#环境变量支持" aria-label="Permalink to &quot;环境变量支持&quot;">​</a></h3><p>目标路径支持以下环境变量，方便指向系统特殊目录：</p><table tabindex="0"><thead><tr><th>变量</th><th>示例解析结果</th></tr></thead><tbody><tr><td><code>%AppData%</code></td><td><code>C:/Users/你的用户名/AppData/Roaming</code></td></tr><tr><td><code>%LocalAppData%</code></td><td><code>C:/Users/你的用户名/AppData/Local</code></td></tr><tr><td><code>%UserProfile%</code> / <code>$HOME</code></td><td><code>C:/Users/你的用户名</code></td></tr></tbody></table><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="批量清理多个场景" tabindex="-1">批量清理多个场景 <a class="header-anchor" href="#批量清理多个场景" aria-label="Permalink to &quot;批量清理多个场景&quot;">​</a></h3><p>可以<strong>分多次扫描同一个目录</strong>，每次使用不同的过滤规则，清理不同的目标。</p><p><strong>示例</strong>: 清理 <code>D:/Projects</code> 目录下的过期依赖和日志</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 1 次扫描: 名称模式 = node_modules，最小年龄 = 30 天，最小大小 = 50MB</span></span>
<span class="line"><span>→ 勾选上大项目，清理 → 释放 2.3GB</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 2 次扫描: 名称模式 = *.log，最小年龄 = 7 天</span></span>
<span class="line"><span>→ 全选 → 清理 → 释放 120MB</span></span></code></pre></div><h3 id="配合二次筛选精细化操作" tabindex="-1">配合二次筛选精细化操作 <a class="header-anchor" href="#配合二次筛选精细化操作" aria-label="Permalink to &quot;配合二次筛选精细化操作&quot;">​</a></h3><p>扫描结果较多时，先用二次筛选缩小范围，再勾选清理。</p><p><strong>示例</strong>: 全盘扫描 <code>.tmp</code> 文件</p><ol><li>目标路径填 <code>C:/</code>，名称模式填 <code>*.tmp</code>，最小大小填 <code>1</code>（只看 1MB 以上的临时文件）</li><li>扫描完成后，在二次筛选区输入 <code>cache</code>，只看名称或路径中包含 <code>cache</code> 的项目</li><li>确认无误后清理</li></ol><h3 id="使用环境变量预填路径" tabindex="-1">使用环境变量预填路径 <a class="header-anchor" href="#使用环境变量预填路径" aria-label="Permalink to &quot;使用环境变量预填路径&quot;">​</a></h3><p>快速指向 VS Code 的全局存储路径来清理编辑器缓存：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>路径: %AppData%/Code/User/globalStorage</span></span>
<span class="line"><span>名称模式: *.cache</span></span>
<span class="line"><span>最小年龄: 30</span></span></code></pre></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="清理后文件去哪里了" tabindex="-1">清理后文件去哪里了？ <a class="header-anchor" href="#清理后文件去哪里了" aria-label="Permalink to &quot;清理后文件去哪里了？&quot;">​</a></h3><p>所有被清理的文件都会被移动到<strong>系统回收站</strong>。如果不小心误删了，可以打开回收站找到对应文件并还原。</p><h3 id="扫描结果里的目录为什么没有大小" tabindex="-1">扫描结果里的目录为什么没有大小？ <a class="header-anchor" href="#扫描结果里的目录为什么没有大小" aria-label="Permalink to &quot;扫描结果里的目录为什么没有大小？&quot;">​</a></h3><p>目录的大小是在扫描过程中<strong>实时计算</strong>的。对于包含大量子文件的目录，大小会在处理完毕后显示。如果目录正在被扫描或计算，会显示 <code>--</code>。</p><h3 id="为什么扫描结果和实际文件数不符" tabindex="-1">为什么扫描结果和实际文件数不符？ <a class="header-anchor" href="#为什么扫描结果和实际文件数不符" aria-label="Permalink to &quot;为什么扫描结果和实际文件数不符？&quot;">​</a></h3><p>扫描受 <code>maxDepth</code>（最大深度）参数限制。如果设置的最大深度为 3，工具只会扫描到第 3 层子目录。需要扫描更深的目录，适当增加该参数即可。</p><h3 id="预设中的-appdata-路径在我的电脑上有效吗" tabindex="-1">预设中的 <code>%AppData%</code> 路径在我的电脑上有效吗？ <a class="header-anchor" href="#预设中的-appdata-路径在我的电脑上有效吗" aria-label="Permalink to &quot;预设中的 \`%AppData%\` 路径在我的电脑上有效吗？&quot;">​</a></h3><p>有效。工具会自动将 <code>%AppData%</code> 等环境变量解析为当前用户的实际路径。如果你在使用 macOS 或 Linux，也可以使用 <code>$HOME</code> 格式的环境变量。</p><h3 id="扫描太慢了-能取消吗" tabindex="-1">扫描太慢了，能取消吗？ <a class="header-anchor" href="#扫描太慢了-能取消吗" aria-label="Permalink to &quot;扫描太慢了，能取消吗？&quot;">​</a></h3><p>可以。扫描过程中点击 <strong>&quot;停止&quot;</strong> 按钮即可随时取消。取消后，已扫描到的结果会保留在结果面板中，你可以直接基于这些结果执行清理。</p>`,57)])])}const g=a(r,[["render",s]]);export{u as __pageData,g as default};
